// Optionbar.js
import React from 'react';
import './Optionbar.css';
import { segmentOptions, locationOptions, seasonOptions, highlightOptions } from './Icons/optionbarOptions';

// Merge all option categories into one array
const allOptions = [
    ...segmentOptions,
    ...locationOptions,
    ...seasonOptions,
    ...highlightOptions,
];

const Optionbar = () => {
    return (
        <div className="optionbar-container">
            <h3 className="optionbar-title">Filters & Categories</h3>
            <ul className="optionbar-list">
                {allOptions.map((option) => (
                    <li key={option.id} className="option-item">
                        <input
                            type="checkbox"
                            id={option.id}
                            defaultChecked={option.checked}
                        />
                        <label htmlFor={option.id} className="option-label">
                            <img
                                src={option.icon}
                                alt={`${option.label} icon`}
                                className="option-icon"
                            />
                            {option.label}
                        </label>
                    </li>
                ))}
            </ul>
        </div>
    );
};

export default Optionbar;
